select i.*, c.category_name, d.dept_name as department_name, u.real_name as owner_user_name from biz_instrument i left join biz_instrument_category c on c.id = i.category_id left join sys_department d on d.id = i.department_id left join sys_user u on u.id = i.owner_user_id where i.deleted = 0
and (i.instrument_name like concat('%', #{keyword}, '%') or i.instrument_no like concat('%', #{keyword}, '%'))
and i.status = #{status}
and i.category_id = #{categoryId}
order by i.sort_no asc, i.id desc limit #{offset}, #{pageSize}


